def bedOverlapCheck(filename):
    if filename.endswith(".gz"):
        f = gzip.open(filename, "r")
    else:
        f = open(filename, "r")
    last = -1
    lines = 1
    thischr = None
    for line in f:
        l = line.split("\t")
        if len(l) < 3:
            continue
        if thischr is not None and thischr != l[0]:
            last = -1
        thischr = l[0]
        if (last - 1) > int(l[1]):
            logging.warn(
                "%s has overlapping regions at %s:%i (line %i)"
                % (filename, l[0], int(l[1]), lines)
            )
            return 1
        last = int(l[2])
        lines += 1
    return 0

