def _process_changes(self, ilayer, olayer, column="gml_id"):
    changes_list = {}
    ilayer.ResetReading()
    ifeature = ilayer.GetNextFeature()
    while ifeature:
        fcode = ifeature.GetField(column)
        found = []
        olayer.SetAttributeFilter("%s = '%s'" % (column, fcode))
        for feature in olayer:
            found.append(feature.GetFID())
        n_feat = len(found)
        changes_list[ifeature.GetFID()] = (
            (Action.update, found[0]) if n_feat > 0 else (Action.add, -1)
        )
        if n_feat > 1:
            VfrLogger.warning(
                "Layer '%s': %d features '%s' found. "
                "Duplicated features will be deleted."
                % (olayer.GetName(), n_feat, fcode)
            )
            for fid in found[1:]:
                olayer.DeleteFeature(fid)
        ifeature = ilayer.GetNextFeature()
    olayer.SetAttributeFilter(None)
    return changes_list

def elapsed_time_string(start_time, stop_time):
    delta_time = stop_time - start_time
    tot_seconds = int(
        (
            delta_time.microseconds
            + (delta_time.seconds + delta_time.days * 24 * 3600) * 10**6
        )
        / 10**6
    )
    years, remainder = divmod(tot_seconds, 365 * 24 * 60 * 60)
    months, remainder = divmod(remainder, 30 * 24 * 60 * 60)
    days, remainder = divmod(remainder, 24 * 60 * 60)
    hours, remainder = divmod(remainder, 60 * 60)
    minutes, seconds = divmod(remainder, 60)
    token_iter = zip(
        [years, months, days, hours, minutes, seconds],
        ["year", "month", "day", "hour", "minute", "second"],
    )
    ret_list = [
        "{token} {token_name}{plural}".format(
            token=num, token_name=desc, plural="s" if num > 1 else ""
        )
        for num, desc in token_iter
        if num > 0
    ]
    if len(ret_list) == 0:
        return "None"
    elif len(ret_list) == 1:
        return ret_list[0]
    elif len(ret_list) == 2:
        return ret_list[0] + " and " + ret_list[1]
    else:
        return (", ".join(ret_list[0:-1])) + " and " + ret_list[-1]

def get_r_threshold_smart(bins, fdr, fdr_threshold, side="left"):
    flag = 1  
    isnan = np.isnan(fdr)
    _y = fdr[~isnan]
    _x = bins[1:][~isnan]
    def f(_x_func):
        return np.interp(_x_func, _x, _y) - fdr_threshold
    if side == "left":
        bins_sub = bins[bins < 0]
    elif side == "right":
        bins_sub = bins[bins > 0]
    else:
        raise ValueError("left or right")
    r_min = bins_sub[np.argmin(f(bins_sub))]
    if f(r_min) * f(0) < 0:
        sol = optimize.root_scalar(f, bracket=(r_min, 0))
        if sol:
            r_threshold = sol.root
            flag = 0
    if flag == 1:
        r_threshold = np.nan
        print("failed to detect r_threshold:")
    if DEBUG_MODE:
        fig, ax = plt.subplots()
        ax.plot(bins, f(bins))
        if flag == 0:
            print(r_threshold, f(r_threshold))
            ax.scatter([r_threshold], [f(r_threshold)])
        plt.show()
    return r_threshold

