def segment_apply_bias(
    segment: Segment, dist: float, normal: np.ndarray
) -> Tuple[float, np.ndarray]:
    bias_segment = segment.bias
    if bias_segment == 0:
        if dist < 0:
            dist = -dist
            normal = -normal
    elif bias_segment < 0:
        bias_segment = -bias_segment
        dist = -dist
        normal = -normal
        if dist < -bias_segment:
            return np.Infinity, normal
    return dist, normal

