def real_array_to_rfft_coeff(
    real_array: np.ndarray, orth_scale: bool = True
) -> np.ndarray:
    rfft_coeffs = real_array[..., : real_array.shape[-1] // 2 + 1] * (1 + 0j)
    rfft_coeffs[..., 1:-1] += real_array[..., real_array.shape[-1] // 2 + 1 :] * 1j
    if orth_scale:
        rfft_coeffs[..., 1:-1] /= 2**0.5
    return rfft_coeffs

