def tokenize_data(data, token_to_id, char_to_id, limit=None):
    tokenized = []
    for qid, passage, query, (start, stop) in data:
        q_tokens, q_chars, _, _, _ = rich_tokenize(
            query, token_to_id, char_to_id, update=True
        )
        p_tokens, p_chars, _, _, mapping = rich_tokenize(
            passage["passage_text"], token_to_id, char_to_id, update=True
        )
        if start == 0 and stop == 0:
            pass  
        elif start == 0 and stop == len(passage):
            stop = len(p_tokens)  
        else:
            t_start = None
            t_end = len(p_tokens)
            for t_ind, (_start, _end) in enumerate(mapping):
                if start < _end:
                    t_start = t_ind
                    break
            assert t_start is not None
            for t_ind, (_start, _end) in enumerate(mapping[t_start:], t_start):
                if stop < _start:
                    t_end = t_ind
                    break
            start = t_start  
            stop = t_end  
        if limit is not None and len(p_tokens) > limit:
            if stop <= limit:
                p_tokens = p_tokens[:limit]
