def topological_sort(nodes, edges):
    iedges = defaultdict(set)  
    backedges = defaultdict(set)
    for a, dsts in edges.items():
        iedges[a] = set(dsts)
        for b in dsts:
            backedges[b].add(a)
    start = []
    for n in nodes:
        if len(backedges[n]) == 0:
            start.append(n)
    result = []
    while start:
        a = start.pop()
        result.append(a)
        nxts = set(iedges[a])
        for b in nxts:
            iedges[a].remove(b)
            backedges[b].remove(a)
            if len(backedges[b]) == 0:
                start.append(b)
    for es in iedges.values():
        if len(es) != 0:
            raise Exception("graph has a loop")
    return result

