def _elastic_net_single(A, b, verbose, lamda_val, alpha_val, opt):
    N, d = A.shape
    if lamda_val == None:
        lamda_val = 0.1
    if alpha_val == None:
        alpha_val = 1.0
    if verbose:
        print(
            "Elastic net regression with lambda=%.2f and alpha=%.2f."
            % (lamda_val, alpha_val)
        )
    if opt == "osqp":
        if verbose:
            print("Solving using cvxpy with OSQP solver")
        b = b.squeeze()
        x = cv.Variable(d)
        lamda1 = cv.Parameter(nonneg=True)
        lamda2 = cv.Parameter(nonneg=True)
        objective = (
            0.5 * cv.sum_squares(A @ x - b)
            + lamda1 * cv.norm1(x)
            + 0.5 * lamda2 * cv.sum_squares(x)
        )
        prob = cv.Problem(cv.Minimize(objective))
        lamda1.value = lamda_val * alpha_val
        lamda2.value = lamda_val * (1.0 - alpha_val)
        prob.solve(solver=cv.OSQP, verbose=verbose)
        x = x.value.reshape(-1, 1)
    elif opt == "scipy":
        raise ValueError(
            "At present cvxpy, must be installed for elastic net regression to be selected."
        )
    return x

