def lineOffsetWithMinimumDistanceToPoint(
    point, line_start, line_end, perpendicular=False
):
    p = point
    p1 = line_start
    p2 = line_end
    d = distance(p1, p2)
    u = ((p[0] - p1[0]) * (p2[0] - p1[0])) + ((p[1] - p1[1]) * (p2[1] - p1[1]))
    if d == 0.0 or u < 0.0 or u > d * d:
        if perpendicular:
            return INVALID_DISTANCE
        if u < 0.0:
            return 0.0
        return d
    return u / d

def draw_box(self, xy=None, bbox=None, flatratio=1.0, **options):
    options = self._check_options(options)
    args = []
    if options["outlinecolor"]:
        pen = aggdraw.Pen(options["outlinecolor"], options["outlinewidth"])
        args.append(pen)
    if options["fillcolor"]:
        brush = aggdraw.Brush(options["fillcolor"])
        args.append(brush)
    if xy:
        x, y = xy
        width = options["fillwidth"]
        height = options["fillheight"]
        if flatratio:
            height *= flatratio
        width, height = (
            width / self.width * self.coordspace_width,
            height / self.height * self.coordspace_height,
        )
        halfwidth, halfheight = width / 2.0, height / 2.0
        bbox = [x - halfwidth, y - halfheight, x + halfwidth, y + halfheight]
    elif bbox:
        pass
    else:
        raise Exception("Either xy or bbox has to be specified")
    self.drawer.rectangle(bbox, *args)

