def sinfilt(arr, Srate, domain=False):
    ind = _np.arange(Srate - 1, len(arr) - 1)
    def sin(k, Srate):
        return _np.sin(2 * _np.pi * k / Srate)
    const = 2 / Srate
    sinf = 0
    for k in range(0, Srate - 1):
        slc = (ind - (Srate - 1)) + k
        sinf += sin(k, Srate) * arr[slc]
    sinf = const * sinf
    if domain:
        xarray = _np.linspace(Srate + Srate / 4 - 1, len(arr) - 1, len(sinf))
        xarray = xarray / Srate
        return sinf, xarray
    return sinf

