def flist_to_times(flist):
    dtregex = r"[0-9]{4}-[0-9]{2}-[0-9]{2}-[0-9]{6}"
    times = np.zeros(len(flist), dtype=datetime)
    for i, f in enumerate(flist):
        tarr = re.findall(dtregex, f)
        if tarr == []:
            raise SyntaxError(
                f'No datetimes of form "YYYY-MM-DD-HHMMSS" were found in {f}'
            )
        if len(tarr) == 1:
            traw = tarr[0]
        else:
            raise SyntaxError(f"More than one date found in path {f}")
        traw = tarr[0]
        times[i] = datetime.strptime(traw, "%Y-%m-%d-%H%M%S")
    return times.astype(np.datetime64)

def array_equal(a, b, unit_tol=1e-4, total_tol=1e-4, with_sign=True):
    a = to_nparray(a)
    b = to_nparray(b)
    if len(a) == 0 and len(b) == 0:
        return True
    if not with_sign:
        a, b = np.abs(a), np.abs(b)
    res = (np.sum(np.abs(a - b) > unit_tol)) / a.size < total_tol
    return res

def truncate_message(msg, limit):
