def __correct_sequence(
    self, seq: torch.Tensor, illuminants: torch.Tensor
) -> torch.Tensor:
    illuminants = illuminants.pow(1.0 / 2.2).permute(1, 0, 2).unsqueeze(3).unsqueeze(4)
    correction = illuminants * torch.sqrt(torch.Tensor([3])).to(self.__device)
    corrected_seq = torch.div(seq, correction + 1e-10)
    max_seq = torch.max(torch.max(torch.max(corrected_seq, dim=2)[0], dim=2)[0], dim=2)[
        0
    ]
    normalized_seq = torch.div(
        corrected_seq, max_seq.unsqueeze(2).unsqueeze(2).unsqueeze(2) + 1e-10
    )
    return normalized_seq

