    params = {}
    if values is not None:
        if not param.endswith("."):
            param = "%s." % param
        for num, value in enumerate(values):
            target_key = "%s%d" % (param, (num + 1))
            if isinstance(value, dict):
                params.update(self.tree2dict(target_key, value))
