def bayes_factor(logw0, logw1):
    c = np.amax(logw0)
    logz0 = c + np.log(np.mean(np.exp(logw0 - c)))
    c = np.amax(logw1)
    logz1 = c + np.log(np.mean(np.exp(logw1 - c)))
    return np.exp(logz1 - logz0)

