def collection_permissions(handler, container=None, target_parent_container=None):
    def g(exec_op):
        def f(method, _id=None, payload=None):
            if method == "GET" and container.get("public", False):
                has_access = True
            elif method == "GET":
                has_access = (
                    _get_access(handler.uid, handler.user_site, container)
                    >= INTEGER_ROLES["ro"]
                )
            elif method == "DELETE":
                has_access = (
                    _get_access(handler.uid, handler.user_site, container)
                    >= INTEGER_ROLES["admin"]
                )
            elif method == "POST":
                has_access = True
            elif method == "PUT":
                has_access = (
                    _get_access(handler.uid, handler.user_site, container)
                    >= INTEGER_ROLES["rw"]
                )
            else:
                has_access = False
            if has_access:
                return exec_op(method, _id=_id, payload=payload)
            else:
                handler.abort(
                    403,
                    "user not authorized to perform a {} operation on the container".format(
                        method
                    ),
                )
        return f
    return g

