    expr = sympify(expr)
    if is_literal(expr):
        return True
    stack = [expr]
    while stack:
        expr = stack.pop()
        if expr.func in (And, Or):
            if simplified:
                args = expr.args
                for arg in args:
                    if Not(arg) in args:
