def _load_with_cypher(self, table_name, data):
    total = len(data)
    for index, row in enumerate(data):
        query = "CREATE ({}:{} ".format(table_name, table_name)
        query += "{ "
        query += ", ".join(
            '{}: "{}"'.format(
                col,
                str(row[col]).replace('"', "'").replace("&", "&.").replace('""', "'"),
            )
            for col in row
        )
        query += "});"
        self._progress(
            index,
            total,
            status="Generating cypher query for table: {}".format(table_name),
        )
        if self.output:
            self._export_file(table_name, [query])
        else:
            pass

