def ihfft(a, n=None, axis=-1, norm=None):
    if n is None:
        n = a.shape[axis]
    if norm is None:
        div = n
    elif norm == "ortho":
        div = 1
    elif norm == "unnormalize":
        div = 1
    else:
        raise ValueError
    return rfft(a, n, axis, norm).conj() / div

def verify_ssh(self, server):
    max_time = self.timeout + time.time()
    running = False
    while max_time > time.time():
        try:
            if ssh.check_ssh(server.public_ip["address"]):
                running = True
                break
        except subprocess.CalledProcessError as exc:
            if (
                "Connection refused" in exc.output
                or "Connection timed out" in exc.output
                or "Connection closed" in exc.output
                or "Connection reset by peer" in exc.output
            ):
                logger.debug(
                    "Waiting for ssh on id:%s ip:%s name:%s remaining:%d",
                    server.id,
                    server.public_ip["address"],
                    server.name,
                    int(max_time - time.time()),
                )
                time.sleep(self.delay)
            else:
                logger.error(
                    "Could not ssh to server name: %s id: %s ip: %s\n%s",
                    server.name,
                    server.id,
                    server.public_ip["address"],
                    exc.output,
                )
                raise
    if running is False:
        raise TimeoutError(
            "Could not provision id:%s name:%s ip:%s before timeout"
            % (server.id, server.name, server.public_ip["address"])
        )

