def refine_work(work, p, new_min, verbose=False, split=False, split_min=4):
    work[p] = work[p][work[p] > new_min]
    if split and not work[p].size:
        big_p, big_arr = sorted(
            work.iteritems(), reverse=True, key=lambda x: x[1].size
        )[0]
        if big_arr.size >= split_min:
            if verbose:
                print(
                    "taking from process {} ({} left) to give "
                    "to process {}".format(big_p, big_arr.size, p)
                )
            work[big_p], work[p] = np.array_split(big_arr, 2)
    return work

def tournament_selection(self):
    i = np.random.randint(0, self.pop_size)
    j = np.random.randint(0, self.pop_size)
    while j == i:
        j = np.random.randint(0, self.pop_size)
    if self.population[i].fitness > self.population[j].fitness:
        return self.population[i]
    return self.population[j]

