def global_norm(t_list, name=None):
    if not isinstance(t_list, collections_abc.Sequence) or isinstance(
        t_list, six.string_types
    ):
        raise TypeError(
            "`t_list` should be a sequence of tensors. Received " f"{type(t_list)}."
        )
    t_list = list(t_list)
    with ops.name_scope(name, "global_norm", t_list) as name:
        values = [
            (
                ops.convert_to_tensor(
                    t.values if isinstance(t, indexed_slices.IndexedSlices) else t,
                    name="t_%d" % i,
                )
                if t is not None
                else t
            )
            for i, t in enumerate(t_list)
        ]
        half_squared_norms = []
        for v in values:
            if v is not None:
                with ops.colocate_with(v):
                    half_squared_norms.append(gen_nn_ops.l2_loss(v))
        half_squared_norm = math_ops.reduce_sum(array_ops.stack(half_squared_norms))
        norm = math_ops.sqrt(
            half_squared_norm
            * constant_op.constant(2.0, dtype=half_squared_norm.dtype),
            name="global_norm",
        )
    return norm

