def rcost(self, y, u):
    if self.y_target == []:
        chi = np.concatenate([y, u])
    else:
        chi = np.concatenate([y - self.y_target, u])
    r = 0
    if self.rcost_struct == 1:
        R1 = self.rcost_pars[0]
        r = chi @ R1 @ chi
    elif self.rcost_struct == 2:
        R1 = self.rcost_pars[0]
        R2 = self.rcost_pars[1]
        r = chi**2 @ R2 @ chi**2 + chi @ R1 @ chi
    return r

