        not self.is_fact(fact)
        or atom.predicate_id != fact.predicate_id
        or len(atom.arguments) != len(fact.arguments)
    ):
        return False
    for i in range(len(atom.arguments)):
        if atom.arguments[i].type is AtomArgType.VARIABLE:
            if (
                atom.arguments[i].arg in bindings
                and bindings[atom.arguments[i].arg] != fact.arguments[i].arg
            ):
                return False
            else:
                bindings[atom.arguments[i].arg] = fact.arguments[i].arg
        elif atom.arguments[i].arg != fact.arguments[i].arg:
            return False
    return bindings

