def make_triangle_periodic(self, size=3):
    if size < 3:
        raise ValueError("size too small")
    n = size * size
    graph = self.cls(n, directed=False)
    weights = list(range(1, 1 + 3 * n))  
    random.shuffle(weights)
    for node in xrange(n):
        graph.add_node(node)
    for node in xrange(n):
        row = node // size
        col = node % size
        graph.add_edge(
            Edge(node, row * size + (col + 1) % size, weights.pop())
        )  
        graph.add_edge(
            Edge(node, ((row + 1) % size) * size + col, weights.pop())
        )  
        graph.add_edge(
            Edge(node, ((row + 1) % size) * size + (col + 1) % size, weights.pop())
        )  
    return graph

