def CNF_to_cnf(cls, cnf):
    def remove_literal(arg):
        return Not(arg.lit) if arg.is_Not else arg.lit
    return And(
        *(Or(*(remove_literal(arg) for arg in clause)) for clause in cnf.clauses)
    )

