def hash(i10):
    if i10 == 0:
        return ALPHA62[0]
    digits = []
    base = len(ALPHA62)
    while i10:
        i10, rem = divmod(i10, base)
        digits.append(ALPHA62[rem])
    digits.reverse()
    return "".join(digits)

