def prob(self, x, name="prob"):
    with ops.name_scope(self.name):
        with ops.op_scope([self.a, self.b, x], name):
            x = ops.convert_to_tensor(x, name="x")
            if x.dtype != self.dtype:
                raise TypeError(
                    "Input x dtype does not match dtype: %s vs. %s"
                    % (x.dtype, self.dtype)
                )
            broadcasted_x = x * self._ones()
            return math_ops.select(
                math_ops.is_nan(broadcasted_x),
                broadcasted_x,
                math_ops.select(
                    math_ops.logical_or(broadcasted_x < self.a, broadcasted_x > self.b),
                    array_ops.zeros_like(broadcasted_x),
                    (1.0 / self.range()) * array_ops.ones_like(broadcasted_x),
                ),
            )

