def edit_entry(
    entry: Entry, attribute: str, raw_new_value: str, attribute_data: AttributeData
) -> Entry:
    if not attribute_data[attribute].editable:
        raise AttributeError("Attribute is read-only")
    new_value = attribute_data[attribute]._run_parser(raw_new_value)
    if attribute == ATTR_TAGS:
        rel_count = len([t for t in new_value if t[0] in "-+"])
        if rel_count not in {0, len(new_value)}:
            raise AttrParseError("Can't both set and add/remove tags")
        tags = set(entry[ATTR_TAGS])
        if "-" in tags or "+" in tags:
            raise AttrParseError("Missing tag name")
        if rel_count == len(new_value):
            for tag in new_value:
                if tag[0] == "-":
                    tags.discard(tag[1:])
                elif tag[0] == "+":
                    tags.add(tag[1:])
            new_value = frozenset(tags)
    return entry.replace(**{attribute: new_value})

