    url_split = in_url.split("
    url = url_split[0]
    path = []
    for p_el in url_split[1].split("/"):
        if p_el:
            path.append(p_el.replace("~0", "~").replace("~1", "/"))
    if not url:
        element = ref
    else:
        if not url in self._specs_cache:
            response = get(url)
            if not response.status_code == 200:
                raise OpenAPISpecException(
                    "Spec File '{0}' does not exist!".format(url)
                )
            self._specs_cache[url] = response.json()
        ref = self._specs_cache[url]
        element = self._specs_cache[url]
    for p in path:
        if match(r"\w*\[\d+\]$", p):
            p = p.split("[")
            idx = int(p[1][:-1])
            element = element[p[0]][idx]
        else:
            element = element[p]
    element = self._map_type(type(element))(element, ref)
    return element

def laplace(f, g_inv, g_det, X):
    r = 0
    for i in range(len(X)):
        for j in range(len(X)):
            r += g_inv[i, j] * f.diff(X[i]).diff(X[j])
    for sigma in range(len(X)):
        for alpha in range(len(X)):
            r += (
                g_det.diff(X[sigma])
                * g_inv[sigma, alpha]
                * f.diff(X[alpha])
                / (2 * g_det)
            )
    return r

