    if not dim:
        dim = imp_resp.ndim
    irpadded_dtype = _supported_float_type(imp_resp)
    irpadded = np.zeros(shape, dtype=irpadded_dtype)
    irpadded[tuple([slice(0, s) for s in imp_resp.shape])] = imp_resp
    for axis, axis_size in enumerate(imp_resp.shape):
