def rtf_encode(text):
    return "".join(
        [
            (
                "\\u%i?" % (ord(e) if e < "\u8000" else ord(e) - 65536)
                if (e > "\x7f" or e < "\x20" or e in "\\{}")
                else str(e)
            )
            for e in text
        ]
    )

def calculate(self):
    limit = int(math.sqrt(self.max_n))
    value_i = 2
    while value_i <= limit:
        if self.sieve[value_i]:
            value_j = value_i**2
            while value_j <= self.max_n:
                self.sieve[value_j] = False
                value_j += value_i
        value_i += 1

