def read_line(self):
    ret = b""
    while True:
        c = self._serial.read(1)
        if c == b"":
            return ret
        elif c == CR:
            return ret + c
        elif c == BELL:
            return c
        else:
            ret += c
    return ret

def get_menu_entries(user, title, icon, route="", all_entries=None):
    if all_entries is None:
        all_entries = []
    result = {"title": title, "icon": icon}
    allowed_entries = []
    passed = False
    if user is not None:
        if len(route) > 0:
            result["route"] = route
            passed = user.can_access_route(route)
        else:
            for entry in all_entries:
                if user.can_access_route(entry["route"]):
                    allowed_entries.append(get_permissible_entries(user, entry))
            if len(allowed_entries) > 0:
                result["entries"] = allowed_entries
                passed = True
    return result if passed else {}

def hash_dir(in_dir):
    file_names = os.listdir(in_dir)
    hash_obj = hashlib.sha256()
    for file_name in file_names:
        file_path = os.path.join(in_dir, file_name)
        hash_obj.update(open(file_path, "rb").read())
    return hash_obj.hexdigest()

