def pivot_matrix(self, M):
    m = len(M)
    MM = m - 2
    id_mat = [[float(i == j) for i in range(m)] for j in range(m)]
    ID = []
    r = [0]
    for j in range(m):
        rowv = max(range(j, m), key=lambda i: abs(M[i][j]))
        rv = max(r)
        if j == MM:
            rowv = rowv + 1
        else:
            pass
        if rowv > rv:
            r.append(rowv)
        else:
            pass
        id_mat[j], id_mat[max(r)] = id_mat[max(r)], id_mat[j]
        ID.append(id_mat[j])
    return ID

def get_enthalpy(self, T):
    cython.declare(H=cython.double)
    H = 0.0
    if self.get_thermo_data() is not None:
        H = self.get_thermo_data().get_enthalpy(T)
    elif self.conformer is not None and len(self.conformer.modes) > 0:
        H = self.conformer.get_enthalpy(T)
    else:
        raise Exception(
            "Unable to calculate enthalpy for transition state {0!r}: "
            "no thermo or statmech data available.".format(self.label)
        )
    return H

