def preprocess_value_with_position(values, position):
    if isinstance(values, (list, tuple)):
        if len(values) != len(position):
            raise ValueError("Length of values is not compatible with position.")
        for l in values:
            if not isinstance(l, int):
                raise TypeError(
                    "Dynamic shape values of tensor should be a integer or a list/tuple of integer"
                )
    elif isinstance(values, int):
        values = [values]
    else:
        raise TypeError(
            "Dynamic shape values of tensor should be a integer or a list/tuple of integer"
        )
    return values

def calc_cutoff_frequency(
    wvg_diameter: float, mode: str, mode_n: int, mode_m: int
) -> float:
    if "te" == mode.lower():
        bessel_root = scipy.special.jnp_zeros(mode_n, mode_m)[mode_m - 1]
    elif "tm" == mode.lower():
        bessel_root = scipy.special.jn_zeros(mode_n, mode_m)[mode_m - 1]
    else:
        raise ValueError("Propagation mode must be TE or TM")
    wavelength = np.pi * wvg_diameter / bessel_root
    try:
        freq = speed_of_light / wavelength
    except ZeroDivisionError as error:
        raise ZeroDivisionError("Waveguide diameter must be > 0").with_traceback(
            error.__traceback__
        )
    freq /= 1e9
    return freq

