def compare_outputs(
    introgressionid_df, hc_df, auto_graph, sample_name, hc_heatmaps, hc_iid_heatmaps
):
    def _count_similar_regions(hc_df):
        """Count number of regions with 1.0"""
        total = 0
        for _, c in hc_df.iterrows():
            if c.Introgressed == 1.0:
                total += 1
                continue
            else:
                continue
        return total
    for row in hc_df.itertuples():
        index = row[0]
        chromosome = row[1]
        position = row[2]
        introgressed = row[3]
        if introgressed == 0:
            continue
        elif (introgressed == 1) and (introgressionid_df.at[position, str(chromosome)]):
            continue
        else:
            if str(hc_df.at[index, "Introgressed"]) == str(np.nan):
                continue
            else:
                hc_df.at[index, "Introgressed"] = 0
    total_common_regions = _count_similar_regions(hc_df)
    print(f"{sample_name}: {total_common_regions}")
    if hc_df.empty:
        return
    else:
        plot_hc_heatmap(
            hc_df,
            f"{sample_name} IntrogressionID",
            hc_heatmaps,
            hc_iid_heatmaps,
            auto_graph,
            just_hc=False,
        )
    return

