def points_2d_inside_image(
    width: int,
    height: int,
    camera_model: str,
    points_2d: np.ndarray,
    points_3d: Optional[np.ndarray] = None,
) -> np.ndarray:
    if (
        camera_model in (CAMERA_MODEL_OPENCV_PINHOLE, CAMERA_MODEL_OPENCV_FISHEYE)
        and points_3d is None
    ):
        raise ValueError(
            f"`points_3d` must be provided for camera model {camera_model}"
        )
    if len(points_2d) != len(points_3d):
        raise ValueError(
            f"Mismatch in length between `points_2d` and `points_3d` with {len(points_2d)} vs. {len(points_3d)}"
        )
    return np.where(
        (points_2d[:, 0] >= 0)
        & (points_2d[:, 0] < width)
        & (points_2d[:, 1] >= 0)
        & (points_2d[:, 1] < height)
        & (
