def auc(actual, posterior, pos_label=1):
    if len(actual) == 0:
        raise Exception("actual is empty")
    if len(posterior) == 0:
        raise Exception("posterior is empty")
    if len(actual) != len(posterior):
        raise Exception("actual and posterior lengths do not match")
    r = tied_rank(posterior)
    positives = np.equal(actual, pos_label)
    num_positive = sum(positives)
    if num_positive == 0:
        raise Exception("actual is has no positives")
    if num_positive == len(actual):
        raise Exception("actual is all positives")
    num_negative = len(actual) - num_positive
    sum_positive = sum(r[positives])
    auc = (sum_positive - num_positive * (num_positive + 1) / 2.0) / (
        num_negative * num_positive
    )
    return auc

def create_surfaces(self) -> dict:
    main_image = pygame.image.load(self.image_path).convert_alpha()
    main_image_height = main_image.get_height()
    main_image_width = main_image.get_width()
    columns = main_image_width / self.width_each
    if columns != int(columns):
        Logger.warn(
            f"The number of columns/frames in the spritesheet ({columns})"
            " is not an integer! This will result in clipped frames!"
        )
    columns = int(columns)
    surfaces = {"forward": [], "backward": []}
    for column in range(columns):
        surface: pygame.Surface = pygame.transform.scale(
            main_image.subsurface(
                pygame.Rect(
                    (column * self.width_each, 0),
                    (self.width_each, main_image_height),
                )
            ),
            self.conversion_size,
        )
        surfaces["forward"].append(pygame.transform.flip(surface, True, False))
        surfaces["backward"].append(surface)
    return surfaces

