def first_order_rdm(data, dist_metric):
    data = data.T
    if dist_metric == 1:
        RDM = 1 - np.corrcoef(data)
    elif dist_metric == 2:
        RDM = cdist(data, data, "euclidean")
    elif dist_metric == 3:
        means = np.mean(data, axis=1)  
        m, n = np.meshgrid(means, means)  
        RDM = abs(m - n)  
    return RDM

