def geo_sim10(a, b):
    prec = max(53, 1 + max(a.e, b.e) - min(a.n, b.n))
    mpfr_a = digital_to_mpfr(a)
    mpfr_b = digital_to_mpfr(b)
    if gmp.is_nan(mpfr_a) or gmp.is_nan(mpfr_b):
        return float("nan")
    if mpfr_a == 0 and mpfr_b == 0:
        return float("inf")
    elif mpfr_a == 0 or mpfr_b == 0:
        return float("-inf")
    with gmp.context(
        precision=prec,
        emin=gmp.get_emin_min(),
        emax=gmp.get_emax_max(),
        trap_underflow=True,
        trap_overflow=True,
        trap_inexact=False,
        trap_invalid=True,
        trap_erange=True,
        trap_divzero=False,
        trap_expbound=False,
    ):
        ratio = mpfr_a / mpfr_b
        if ratio <= 0:
            return float("-inf")
        reldiff = abs(gmp.log10(ratio))
    with gmp.ieee(64):
        sim = -gmp.log10(reldiff)
    return float(sim)

