def get_prev_ckpt(outdir):
    prev_run_dirs = []
    if os.path.isdir(outdir):
        prev_run_dirs = [
            x for x in os.listdir(outdir) if os.path.isdir(os.path.join(outdir, x))
        ]
    prev_run_ids = [re.match(r"^\d+", x) for x in prev_run_dirs]
    prev_run_ids = [int(x.group()) for x in prev_run_ids if x is not None]
    latest_run_id = max(prev_run_ids, default=-1)
    if latest_run_id == -1:
        return ""
    else:
        latest_run_dir = [
            x for x in prev_run_dirs if x.startswith(f"{latest_run_id:05d}")
        ][0]
        pkl_files = [
            x
            for x in os.listdir(os.path.join(outdir, latest_run_dir))
            if x.startswith("network-snapshot")
        ]
        ticks = [int(x.split(".")[0].split("-")[-1]) for x in pkl_files]
        latest_tick = max(ticks, default=0)
        latest_pkl_name = f"network-snapshot-{latest_tick:06d}.pkl"
        prev_pkl_path = os.path.join(outdir, latest_run_dir, latest_pkl_name)
        return prev_pkl_path

