def recursive_merge(dfs, on=None, how="inner", columns={}):
    data = dfs[0]
    for i, d in enumerate(dfs[1:], 1):
        if columns.get(str(i)):
            cols = list(columns.get(str(i)))
            cols.extend(on)
        else:
            cols = d.columns
        if on is None:
            data = data.merge(d[cols], how=how, left_index=True, right_index=True)
