def unify_bucket_name_and_key(func: T) -> T:
    function_signature = signature(func)
    @wraps(func)
    def wrapper(*args, **kwargs) -> T:
        bound_args = function_signature.bind(*args, **kwargs)
        def get_key() -> Optional[str]:
            if "key" in bound_args.arguments:
                return "key"
            raise ValueError("Missing key parameter!")
        key_name = get_key()
        if (
            "bucket_name" not in bound_args.arguments
            or bound_args.arguments["bucket_name"] is None
        ):
            bound_args.arguments["bucket_name"], bound_args.arguments["key"] = (
                OSSHook.parse_oss_url(bound_args.arguments[key_name])
            )
        return func(*bound_args.args, **bound_args.kwargs)
    return cast(T, wrapper)

