def symlink(
    self, source: Union[str, pathlib.Path], destination: Union[str, pathlib.Path]
) -> None:
    src = _path_to_posix_str(path=source)
    dst = _path_to_posix_str(path=destination)
    try:
        self._sftp.lstat(dst)
        raise FileExistsError(
            "The destination of the symbolic link already exists: {}".format(dst)
        )
    except FileNotFoundError:
        pass
    try:
        self._sftp.symlink(source=src, dest=dst)
    except OSError as err:
        raise OSError(
            "Failed to create the symbolic link to {} at {}".format(src, dst)
        ) from err

def add_relative(self, what):
    if isinstance(what, URL_base):
        return what
    if 0 == len(what):
        return URL(self)
    if what[0] == "/":
        if 1 == len(what) or what[1] != "/":
            url = URL_base(self)
            url.path = what
            return URL(url.asString())
        else:
            return URL(self.scheme + ":" + what)
    url = URL_base(self)
    spl1 = url.path.split("/")[1:]
    if len(spl1) and spl1[-1] == "":
        spl1 = spl1[:-1]
    spl2 = what.split("/")
    for pcomp in spl2:
        if pcomp == ".":
            pass
        elif pcomp == "..":
            spl1 = spl1[:-1]
        else:
            spl1.append(pcomp)
    url.path = "/" + "/".join(spl1)
    return URL(url.asString())

