    dpm = np.arctan2(moms_peak, momc_peak) * (
        ipeak * 0 + 1
    )  
    dpm = (270 - R2D * dpm) % 360.0
    dpm.attrs.update(
        {
            "standard_name": self._standard_name(self._my_name()),
            "units": self._units(self._my_name()),
        }
    )
    return dpm.where(ipeak > 0).fillna(mask).rename(self._my_name())

