        try:
            return method(self, *args, **kwargs)
        except Exception as raised_exception:
            self.logger.error(
                "Problem during the execution of {method}".format(
                    method=method.__name__
                )
            )
            template = "An exception of type {0} occurred. Arguments: {1!r}"
