def _transform_coordinate_system(pointlist):
    a, b, c, d = pointlist - pointlist[0]
    angle = math.atan2(1, 1) - math.atan2(
        b[1], b[0]
    )  
    rot_matrix = np.array(
        [[math.cos(angle), -math.sin(angle)], [math.sin(angle), math.cos(angle)]]
    )
    b, c, d = [rot_matrix.dot(v) for v in [b, c, d]]  
    return [0, 0], b, c, d

