def _RemoveEdges(tris, match):
    ans = []
    triset = set(tris)
    while len(match) > 0:
        (_, e, tl, tr) = match.pop()
        (a, b) = e
        if tl in triset:
            triset.remove(tl)
        if tr in triset:
            triset.remove(tr)
        c = _OtherVert(tl, a, b)
        d = _OtherVert(tr, a, b)
        if c is None or d is None:
            continue
        ans.append((a, d, b, c))
    return ans + list(triset)

def traveling_salesman_qubo(G, lagrange=2.0):
    if not G:
        return {}
    N = G.number_of_nodes()
    Q = {}
    Q = {
        ((node_1, pos_1), (node_2, pos_2)): 0.0
        for node_1 in G
        for node_2 in G
        for pos_1 in range(N)
        for pos_2 in range(N)
    }
    for node in G:
        for pos_1 in range(N):
            Q[((node, pos_1), (node, pos_1))] -= lagrange
            for pos_2 in range(pos_1 + 1, N):
                Q[((node, pos_1), (node, pos_2))] += 2.0 * lagrange
    for pos in range(N):
        for node_1 in G:
            Q[((node_1, pos), (node_1, pos))] -= lagrange
            for node_2 in set(G) - {node_1}:
                Q[((node_1, pos), (node_2, pos))] += 2.0 * lagrange
    for node_1 in G:
        for node_2 in G:
            if node_1 < node_2:
                for pos in range(N):
                    Q[((node_1, pos), (node_2, (pos + 1) % N))] += G[node_1][node_2][
                        "weight"
                    ]
    return Q

