def _pop_multiple(d, default, *args):
    assert len(args) > 0, "You must provide at least one argument to 'pop'."
    results = []
    for k in args:
        try:
            results.append((k, d.pop(k)))
        except KeyError:
            pass
    if len(results) > 1:
        raise TypeError(
            "The arguments ({0}) are equivalent, you can only ".format(
                ", ".join([k for k, v in results])
            )
            + "provide one of them."
        )
    if len(results) == 0:
        return default
    return results[0][1]

