def guassian_kernel(X, alpha) -> np.array:
    norms_1 = (X**2).sum(axis=1)
    norms_2 = (X**2).sum(axis=1)
    dists = np.abs(norms_1.reshape(-1, 1) + norms_2 - 2 * np.dot(X, X.T))
    return np.exp(-dists / (2 * (alpha**2)))

