def kv_depth(d, depth, _counter=1):
    if depth == 0:
        yield d[_meta]["_rootname"], d
    else:
        if _counter == depth:
            for key, node in DictTree.kv(d):
                yield key, node
        else:
            _counter += 1
            for node in DictTree.v(d):
                for key, node in DictTree.kv_depth(node, depth, _counter):
                    yield key, node

def default_mapping_deserializer(obj: dict, cls: type, **kwargs) -> Mapping:
    cls_ = Mapping
    if hasattr(cls, "__args__"):
        cls_ = MappingType[cls.__args__]
    dict_ = default_dict_deserializer(obj, cls_, **kwargs)
    result = dict_
    naked_cls = get_naked_class(cls)
    if not isinstance(result, naked_cls):
        result = cls(dict_)
    return result

