def static_layout(self, graph):
    next_pos = {}
    already_there = []
    limit = 5
    curr_x = 0
    curr_y = 0
    step = 1
    for [s, p, o] in self.curr_triples:
        if (
            "image" not in s
            and "image" not in p
            and "image" not in o
            and p not in next_pos.keys()
        ):
            curr_x, curr_y, step = self.update_node_pos(
                next_pos, already_there, curr_x, curr_y, [s, p, o], step
            )
            curr_y += 1
    curr_x = 0
    for k in graph.nodes:
        if k not in next_pos.keys():
            next_pos[k] = [step * curr_x, curr_y]  
            curr_x += 1
            if curr_x == limit:
