def sample(self, query_str, relevant_docs, max_query_len=512):
    query_str = query_str[-max_query_len:]
    sampled_initial = [
        hit.raw
        for hit in self.searcher.search(query_str, k=self.num_candidates_samples)
    ]
    was_relevant_sampled = False
    relevant_doc_rank = -1
    sampled = []
    for i, d in enumerate(sampled_initial):
        if d in relevant_docs:
            was_relevant_sampled = True
            relevant_doc_rank = i
        else:
            sampled.append(d)
    while len(sampled) != self.num_candidates_samples:
        sampled = sampled + [
            d
            for d in random.sample(
                self.candidates, self.num_candidates_samples - len(sampled)
            )
            if d not in relevant_docs
        ]
    return sampled, was_relevant_sampled, relevant_doc_rank

