def __init__(self, model, epsilon, num_steps, step_size, loss_func):
    self.model = model
    self.epsilon = epsilon
    self.num_steps = num_steps
    self.step_size = step_size
    if loss_func == "xent":
        loss = model.xent
    elif loss_func == "cw":
        label_mask = tf.one_hot(
            model.y_input, 10, on_value=1.0, off_value=0.0, dtype=tf.float32
        )
        correct_logit = tf.reduce_sum(label_mask * model.pre_softmax, axis=1)
        wrong_logit = tf.reduce_max(
            (1 - label_mask) * model.pre_softmax - 1e4 * label_mask, axis=1
        )
        loss = -tf.nn.relu(correct_logit - wrong_logit + 0)
    else:
        print("Unknown loss function. Defaulting to cross-entropy")
        loss = model.xent
    self.grad = tf.gradients(loss, model.x_input)[0]

