def adjax_response(func):
    template_name = None
    def wrapper(request, *args, **kw):
        output = func(request, *args, **kw)
        store = get_store(request)
        if output is None:
            output = {}
        elif isinstance(output, dict):
            output = output.copy()
            output.pop("request", None)
            for key, val in output.items():
                store.extra(key, val)
        elif isinstance(output, HttpResponse) and output.status_code in (301, 302):
            store.redirect(output["Location"])
        if request.is_ajax():
            return store.json_response(include_messages=True)
        if isinstance(output, dict):
            if template_name:
                output.setdefault(ADJAX_CONTEXT_KEY, store)
                return render_to_response(
                    template_name, output, context_instance=RequestContext(request)
                )
            if "HTTP_REFERER" in request.META:
                return redirect(request.META["HTTP_REFERER"])
            elif DEFAULT_REDIRECT:
                return redirect(DEFAULT_REDIRECT)
            else:
                return HttpResponse()
        return output
    return wrapper

def checkLoop(self):
    while True:
        while self.processSpec == []:
            sleep(1)
        for i in range(0, len(self.processSpec)):
            try:
                procPri = self.processSpec[i][0].nice()
                if procPri != self.processSpec[i][1]:
                    if self.clearToPrint == 1:
                        print(
                            f"Process {self.processSpec[i][1]} has changed its priority to {procPri}"
                        )
                    self.processSpec[i][0].nice(self.processSpec[i][1])
            except psutil.NoSuchProcess:
                if self.clearToPrint == 1:
                    print(
                        f"Process {self.processSpec[i][1]} no-longer exists, removing from targets."
                    )
                self.processSpec.pop(i)
        sleep(1)

