    dM = state_2.ML - state_1.ML
    if (abs(dL) == 1) and (abs(dM) <= 1):
        p = kwargs.get("p", 1.0)
        return self.angular_overlap(
            state_1.L, state_2.L, state_1.ML, state_2.ML, **kwargs
