def geometric_mean(data):
    ap = add_partial
    log = math.log
    partials = []
    count = 0
    try:
        for x in data:
            count += 1
            ap(log(x), partials)
    except ValueError:
        if x < 0:
            raise StatsError("geometric mean of negative number")
        return 0.0
    if count == 0:
        raise StatsError("geometric mean of empty sequence is not defined")
    p = math.exp(math.fsum(partials))
    return pow(p, 1.0 / count)

