def quatRot(q, v):
    if len(np.shape(q)) == 1:
        q = np.expand_dims(q, axis=0)
        array = 0
    else:
        array = 1
    if len(np.shape(v)) == 1:
        v = np.expand_dims(v, axis=0)
    else:
        array = 1
    n1 = np.shape(q)[0]
    n2 = np.shape(v)[0]
    assert (
        n1 == n2 or n1 == 1 or n2 == 1
    ), "Number of quaternions and vectors in arrays do not match"
    result = np.empty((max(n1, n2), 3))
    t = 2.0 * np.cross(q[:, 1:4], v)
    result = v + (q[:, 0] * t.T).T + np.cross(q[:, 1:4], t)
    if array == 0:
        result = np.squeeze(result)
    return result

