    list_len = len(input_list)
    if list_len < 2:
        return []
    return_list = [0, 0]
    heapsort(input_list)
    return_index = 0
    multiplier = 1
    for i in range(list_len):
        return_list[return_index] += input_list[i] * multiplier
        if return_index == 1:
            return_index = 0
            multiplier *= 10
        else:
            return_index = 1
    return return_list

