def sort_n_time(func, temp_list):
    times = []
    count = 0
    for element in temp_list:
        if func.__name__ == "quick_sort":
            start = time.time()
            func(element, 0, len(element) - 1)
            end = time.time()
        else:
            start = time.time()
            func(element)
            end = time.time()
            count += 1
        times.append(end - start)
    return sum(times) / len(times)

