def min_window(
    shared,
    history_len,
    future_len,
    out_arr,
    window_size,
    forward_window_size,
    arr_len,
    offset,
    min_size,
):
    for i in range(arr_len):
        if i + history_len < window_size - 1:
            out_arr[i] = np.nan
        elif future_len - i < forward_window_size + 1:
            out_arr[i] = np.nan
        else:
            s = np.inf  
            average_size = 0
            for j in range(0, window_size + forward_window_size):
                if not (cmath.isnan(shared[offset + i - j + forward_window_size])):
                    if shared[i + offset - j + forward_window_size] < s:
                        s = shared[i + offset - j + forward_window_size]
                    average_size += 1
            if average_size >= min_size:
                out_arr[i] = s
            else:
                out_arr[i] = np.nan

