def deserialize(response_entity_type):
    def decorator(f):
        def wrapper(*args, **kwargs):
            response = f(*args, **kwargs)
            setattr(response.request, "entity", None)
            setattr(response, "entity", None)
            deserialize_format = None
            content_type = response.headers.get("content-type", "")
            formats = ["text", "json", "xml"]
            for format_ in formats:
                if format_ in content_type:
                    deserialize_format = format_
                    break
            resp_entity = response_entity_type.deserialize(
                response.content, deserialize_format
            )
            setattr(response, "entity", resp_entity)
            return response
        return wrapper
    return decorator

def chebfromroots(roots):
    if len(roots) == 0:
        return np.ones(1)
    else:
        [roots] = pu.as_series([roots], trim=False)
        roots.sort()
        p = [chebline(-r, 1) for r in roots]
        n = len(p)
        while n > 1:
            m, r = divmod(n, 2)
            tmp = [chebmul(p[i], p[i + m]) for i in range(m)]
            if r:
                tmp[0] = chebmul(tmp[0], p[-1])
            p = tmp
            n = m
        return p[0]

def _iterImageSections(
    image: Image, sections: SectionMap
) -> Iterator[tuple[Section, bytes]]:
    imageEnd = len(image)
    offset = 0
    for section in sections:
        prevEnd = min(section.start, imageEnd)
        if offset < prevEnd:
            yield Section(offset, prevEnd, "gap"), image[offset:prevEnd]
        if prevEnd == imageEnd:
            break
        end = cast(int, min(section.end, imageEnd))
        yield section, image[prevEnd:end]
        offset = end
    if offset < imageEnd:
        yield Section(offset, imageEnd, "gap"), image[offset:imageEnd]

