def _finite_helper(phase, transparency, temperature, gap):
    sq = np.sqrt(1 - transparency * np.sin(phase / 2) ** 2)
    cpr = np.sin(phase) / sq
    if temperature != 0:
        cpr *= np.tanh(gap / (2 * cs.Boltzmann * temperature) * sq)
    return cpr

