                    if c > 4 and r == 4
                    else (
                        0x100 << c
                        if c == 8 - r and c < 4
                        else (
                            0x100 << (c - 1)
                            if c == 8 - r and c > 4
                            else (
                                0x10000 << 8 - r - 1
                                if r < 4 and c == 4
                                else (
                                    0x10000 << 8 - r
                                    if r > 4 and c == 4
                                    else (
                                        0x1000000 << 8 - c - 1
                                        if c == r and c < 4
                                        else (
                                            0x1000000 << 8 - c
                                            if c == r and c > 4
                                            else 0
                                        )
                                    )
                                )
                            )
                        )
                    )
                )
            )
            for c in range(9)
        ]
        for r in range(9)
    ]
    self.impacts = [[self.impact_from(r, c) for c in range(size)] for r in range(size)]
    self.compute_edges()
    GomokuBoard.__init__(self, size, disp_width, stones)

