def _parse_loops_from_graph(self, graph):
    outtop = []
    outall = []
    for subg in networkx.strongly_connected_component_subgraphs(graph):
        if len(subg.nodes()) == 1:
            if len(subg.successors(subg.nodes()[0])) == 0:
                continue
        thisloop, allloops = self._parse_loop_graph(subg, graph)
