def field_tag(parser, token):
    error_msg = (
        "%r tag requires a form field followed by a list of attributes and values in "
        'the form attr="value"' % token.split_contents()[0]
    )
    try:
        bits = token.split_contents()
        form_field = bits[1]
        attr_list = bits[2:]
    except ValueError:
        raise TemplateSyntaxError(error_msg)
    form_field = parser.compile_filter(form_field)
    set_attrs = []
    append_attrs = []
    for pair in attr_list:
        match = ATTRIBUTE_RE.match(pair)
        if not match:
            raise TemplateSyntaxError(error_msg + ": %s" % pair)
        dct = match.groupdict()
        attr, sign, value = (
            dct["attr"],
            dct["sign"],
            parser.compile_filter(dct["value"]),
        )
        if sign == "=":
            set_attrs.append((attr, value))
        else:
            append_attrs.append((attr, value))
    return FieldAttributeNode(form_field, set_attrs, append_attrs)

def get_fragment_octaves(self, fragment=None, reference=None):
    self._check_database()
    if fragment is None and reference is None:
        return [
            list(x)
            for x in self.cursor.execute(
                "SELECT fragment, community_reference, octave, richness"
                " FROM FRAGMENT_OCTAVES"
            )
        ]
    elif fragment is None or reference is None:
        raise SyntaxError(
            "Only one of fragment or reference supplied: must supply both, or neither."
        )
    try:
        output = [
            list(x)
            for x in self.cursor.execute(
                "SELECT octave, richness FROM FRAGMENT_OCTAVES WHERE "
                "community_reference == ? AND fragment == ?",
                (reference, fragment),
            ).fetchall()
        ]
        if len(output) == 0:
            raise RuntimeError(
                "No output while fetching fragment data for {} with ref: {}".format(
                    fragment, reference
                )
            )
    except sqlite3.Error as oe:
        raise sqlite3.Error("Failure whilst fetching fragment octave data." + str(oe))
    output.sort(key=lambda x: x[0])
    return output

