        qc_loc = Path(dirpath)
        for fname in filenames:
            if not fname.endswith(".qc"):
                continue
            qc_path = qc_loc / fname
            qc_result = parse_qc(qc_loc, qc_path)
            if qc_result is None:
                continue
            (
                model_name,
                ref_scale,
                ref_smd,
                phy_scale,
                phy_smd,
