def filtering(
    data,
    wgts,
    mode="valid",
    dim=1,
    axis=None,
    fft=False,
    fftn=np.fft.fftn,
    ifftn=np.fft.ifftn,
):
    if isinstance(data, np.ma.MaskedArray):
        mask = data.mask  
        indata = np.ma.filled(data, 0)
    else:
        indata = np.copy(data)
    if dim == 1:
        if axis is None:
            data_conv = signal.convolve(indata, wgts, mode=mode)
        else:
            data_conv = np.apply_along_axis(
                signal.convolve, axis, indata, wgts, mode=mode
            )
    elif dim == 2:
        if fft:
            data_conv = convolve_fft(indata, wgts, fftn=fftn, ifftn=ifftn)
        else:
            data_conv = signal.convolve2d(indata, wgts, mode=mode, boundary="symm")
    if isinstance(data, np.ma.MaskedArray):
        data_conv[mask] = np.nan
    return data_conv

def _eval(self, context: RuleContext) -> Optional[List[LintResult]]:
    if context.segment.is_type("orderby_clause"):
        lint_fixes = []
        orderby_spec = self._get_orderby_info(context.segment)
        order_types = {o.order for o in orderby_spec}
        if None not in order_types or order_types == {None}:
            return None
        for col_info in orderby_spec:
            if not col_info.order:
                lint_fixes.append(
                    LintFix.create_before(
                        col_info.separator,
                        [WhitespaceSegment(), KeywordSegment("ASC")],
                    )
                )
        return [
            LintResult(
                anchor=context.segment,
                fixes=lint_fixes,
                description=(
                    "Ambiguous order by clause. Order by clauses should specify "
                    "order direction for ALL columns or NO columns."
                ),
            )
        ]
    return None

