        for name in filenames:
            if name.endswith(extension) and not "Generated" in name:
                path = os.path.join(dirpath, name)
                with open(path, "r") as source_file:
                    line_number = 0
                    prev_line = None
                    for line in source_file.readlines():
                        line_number += 1
                        if (
                            re.search(regex, line)
