            newrefs = []
            for r in ref:
                if r < min:
                    newrefs.append(base_type._decode(r, {}, None))
                else:
                    newrefs.append(types[r])
            newrefs = ListContainer(newrefs)
            setattr(leaf, attr, newrefs)
        else:
            if ref < min:
