def _data_partitions(data, permutations, size_a, axis=-1, random_state=None):
    random_state = check_random_state(random_state)
    if axis < 0:  
        axis = data.ndim + axis
    size = data.shape[axis]
    n_max = special.comb(size, size_a)
    if permutations < n_max:
        indices = np.array(
            [random_state.permutation(size) for i in range(permutations)]
        ).T
    else:
        permutations = n_max
        indices = np.array(
            [np.concatenate(z) for z in _all_partitions(size_a, size - size_a)]
        ).T
    data = data.swapaxes(axis, -1)  
    data = data[..., indices]  
    data = data.swapaxes(-2, axis)  
    data = np.moveaxis(data, -1, 0)  
    return data, permutations

