def _check_fit(
    self, item_width: int, item_height: int, sky_index: int
) -> Tuple[bool, int]:
    i = sky_index
    x = self.skyline[i].x
    y = self.skyline[i].y
    width = item_width
    if x + item_width > self.width:
        return (False, None)
    if y + item_height > self.height:
        return (False, None)
    while width > 0:
        y = max(y, self.skyline[i].y)
        if y + item_height > self.height:
            return (False, None)
        width -= self.skyline[i].width
        i += 1
        if width > 0 and i == len(self.skyline):
            return (False, None)
    return (True, y)

